@app.route('/login', methods=['POST'])
def login():
    data = request.get_json() or {}
    username = data.get('username', 'guest')
    
    session['username'] = username
    session['user_id'] = data.get('user_id', 1)
    session['logged_in'] = True
    
    return jsonify({
        'message': 'Logged in successfully',
        'username': username,
        'session_id': session.sid
    })


@app.route('/profile')
def profile():
    if not session.get('logged_in'):
        return jsonify({'error': 'Not logged in'}), 401
    
    return jsonify({
        'username': session.get('username'),
        'user_id': session.get('user_id'),
        'session_id': session.sid
    })


@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})


@app.route('/user/<int:user_id>')
def get_user(user_id):
    user = get_user_from_db(user_id)
    return jsonify({
        'user': user,
        'cached': True
    })


@app.route('/products')
def get_products():
    category = request.args.get('category')
    limit = int(request.args.get('limit', 10))
    
    products = get_products_from_db(category=category, limit=limit)
    return jsonify({
        'products': products,
        'count': len(products),
        'cached': True
    })


@app.route('/invalidate/user/<int:user_id>', methods=['POST'])
def invalidate_user_cache(user_id):
    get_user_from_db.invalidate_cache(user_id)
    return jsonify({'message': f'Cache invalidated for user {user_id}'})


@app.route('/invalidate/products', methods=['POST'])
def invalidate_products_cache():
    invalidate_cache_pattern('db:products:*')
    return jsonify({'message': 'All product caches invalidated'})


@app.route('/cache/stats')
def cache_stats():
    info = redis_client.info('stats')
    dbsize = redis_client.dbsize()
    
    return jsonify({
        'total_keys': dbsize,
        'keyspace_hits': info.get('keyspace_hits', 0),
        'keyspace_misses': info.get('keyspace_misses', 0),
        'connected_clients': info.get('connected_clients', 0)
    })


@app.route('/session/count')
def session_count():
    session_keys = redis_client.keys('session:*')
    return jsonify({
        'active_sessions': len(session_keys)
    })


